#include <bits/stdc++.h>
using namespace std;

class Solution {
public:
    double myPow(double x, int n) {
        if (n == 0) return 1.0;
        if (x == 0.0) return (n > 0) ? 0.0 : INFINITY;
        long long exp = n;
        bool negative = false;
        if (exp < 0) {
            negative = true;
            exp = -exp;
        }
        double result = 1.0;
        double base = x;
        while (exp) {
            if (exp & 1LL) result *= base;
            base *= base;
            exp >>= 1LL;
        }
        return negative ? 1.0 / result : result;
    }
};

int main() {
    ios::sync_with_stdio(false);
    cin.tie(nullptr);
    double x;
    int n;
    if (!(cin >> x)) return 0;
    if (!(cin >> n)) return 0;
    Solution sol;
    double ans = sol.myPow(x, n);
    // format output similar to Python version
    std::ostringstream oss;
    oss << fixed << setprecision(10) << ans;
    string s = oss.str();
    // strip trailing zeros and possible dot
    while (!s.empty() && s.back() == '0') s.pop_back();
    if (!s.empty() && s.back() == '.') s.pop_back();
    if (s.empty()) s = "0";
    cout << s;
    return 0;
}
